def binary_search(arr, l, r, x):
    # Base case
    if r >= l:
        # Key exists in array
        if arr[r] == x:
            return r
        # Key doesn't exist in array
        return -1
    # Key not found
    return -1

def findCommonElements(arr1, arr2):
    # create an empty list to store the common elements
    common_elems = []

    # loop through the elements of arr1 and check for their presence in arr2
    for i in arr1:
        if i in arr2:
            common_elems.append(i)

    # return the common elements
    return common_elems
